// معالجة صفحة هيئة الخبراء
const inputData = $input.first();
const html = inputData && inputData.json ? (inputData.json.data || inputData.json.body || '') : '';
const knownLaws = [
  { id: 'labor', name: 'نظام العمل', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=1' },
  { id: 'companies', name: 'نظام الشركات', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=2' },
  { id: 'procurement', name: 'نظام المنافسات والمشتريات الحكومية', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=3' },
  { id: 'vat', name: 'نظام ضريبة القيمة المضافة', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=4' },
  { id: 'anticorruption', name: 'نظام مكافحة الفساد', url: 'https://www.boe.gov.sa/ar/LegalDocuments/Pages/LawDetails.aspx?LawID=5' }
];
return knownLaws.map(function(law) {
  return { json: { source: 'boe', source_name: 'هيئة الخبراء بمجلس الوزراء', law_id: law.id, law_name: law.name, url: law.url, fetched_at: new Date().toISOString() } };
});

// معالجة صفحة أم القرى
const inputData = $input.first();
const html = inputData && inputData.json ? (inputData.json.data || inputData.json.body || '') : '';
const today = new Date();
const fallback = [0,1,2,3].map(function(i) {
  const d = new Date(today);
  d.setDate(today.getDate() - i*7);
  return { json: { source: 'uqn_fallback', source_name: 'جريدة أم القرى الرسمية', url: 'https://www.uqn.gov.sa/issues', approximate_date: d.toISOString().split('T')[0], fetched_at: new Date().toISOString() } };
});
if (html.length < 100) { return fallback; }
const issueRegex = /href="([^"]*issue[^"]*)"/gi;
const issues = [];
let match;
while ((match = issueRegex.exec(html)) !== null) {
  issues.push({ json: { source: 'uqn', source_name: 'جريدة أم القرى الرسمية', url: match[1].startsWith('http') ? match[1] : 'https://www.uqn.gov.sa' + match[1], fetched_at: new Date().toISOString() } });
}
return issues.length > 0 ? issues.slice(0, 4) : fallback;

// استخراج النص من HTML بدون Tika
const item = $input.item;
const html = item.json.data || item.json.body || '';
const source = item.json.source || 'unknown';
const lawName = item.json.law_name || item.json.source_name || 'وثيقة قانونية';
const url = item.json.url || '';
const lawId = item.json.law_id || item.json.approximate_date || String(Date.now());
let text = html
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/\s+/g, ' ')
  .trim();
if (text.length < 50) { text = lawName + ' - ' + url; }
const safeId = (source + '_' + lawId).replace(/[^a-zA-Z0-9_]/g, '_').substring(0, 60);
const filename = safeId + '_' + new Date().toISOString().split('T')[0] + '.txt';
return [{ json: { ...item.json, extracted_text: text, filename: filename, char_count: text.length } }];

// تجهيز البيانات للإرسال المباشر إلى ChromaDB عبر Ollama
const item = $input.first();
const text = item.json.text || '';
const source = item.json.source || 'unknown';
const lawName = item.json.law_name || '';
const lawId = item.json.law_id || '';
const url = item.json.url || '';
const approxDate = item.json.approximate_date || '';

if (!text || text.length < 50) {
  return [{ json: { skip: true, reason: 'text too short' } }];
}

// Split text into chunks of ~500 chars with overlap
const chunkSize = 500;
const overlap = 50;
const chunks = [];
let start = 0;
while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunk = text.substring(start, end).trim();
  if (chunk.length > 30) {
    chunks.push(chunk);
  }
  start += chunkSize - overlap;
}

if (chunks.length === 0) {
  return [{ json: { skip: true, reason: 'no chunks' } }];
}

const timestamp = Date.now();
const results = chunks.map((chunk, i) => ({
  json: {
    chunk_text: chunk,
    chunk_id: `${source}_${lawId}_${timestamp}_${i}`,
    metadata: {
      source: source,
      law_name: lawName,
      law_id: lawId,
      url: url,
      approximate_date: approxDate,
      chunk_index: i,
      total_chunks: chunks.length
    }
  }
}));

return results;

const items = $input.all();
const count = items.length;
const names = items.map(function(i) { return i.json.law_name || i.json.source_name || '?'; });
console.log('تم حفظ ' + count + ' وثيقة في knowledge_inbox');
return [{ json: { saved_count: count, documents: names, timestamp: new Date().toISOString(), status: 'success' } }];
